package logic_building;

public class swap_tnumber {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int a =10;
		int b= 20;
		int c= 30;
	
		System.out.println("before swap value is  "   +a);
		System.out.println("before swap value is  "   +b);
		System.out.println("before swap value is  "   +c);
		a=a+b; //30
		b=a-b;//10 
		c=a-b; // 20 
	
		System.out.println("  " +a);
		System.out.println(" "  +b);
		System.out.println("  "   +c);
		
	}

}
